359: // ── Exported API ─────────────────────────────────────────────────────
360: 
361: export fn state_size() usize {
362:     return @sizeOf(State);
363: }
364: 
365: export fn init_state(state: *anyopaque) void {
366:     const s: *State = @ptrCast(@alignCast(state));
367:     s.* = std.mem.zeroes(State);
368: }
369: 
370: export fn reset(state: *anyopaque) void {
371:     const s: *State = @ptrCast(@alignCast(state));
372:     s.* = std.mem.zeroes(State);
373: }
374: 
375: export fn backspace(state: *anyopaque) u8 {
376:     const s: *State = @ptrCast(@alignCast(state));
377:     if (s.len == 0) return 0;
378:     s.len -= 1;
379:     // Clear the removed span
380:     s.spans[s.len] = std.mem.zeroes(Span);
381:     // If all spans removed, reset mode
382:     if (s.len == 0) s.mode = 0;
383:     return 1;
384: }
385: 
386: export fn add(state: *anyopaque, char_code: u16) u8 {
387:     const s: *State = @ptrCast(@alignCast(state));
388: 
389:     // Only handle ASCII range
390:     if (char_code > 127) {
391:         reset(state);
392:         return 0;
393:     }
394:     const ch: u8 = @intCast(char_code);
395: 
396:     // Non-alphanumeric → reset and passthrough
397:     if (!isAlpha(ch)) {
398:         reset(state);
399:         return 0;
400:     }
401: 
402:     const lo = toLower(ch);
403:     const is_upper = ch >= 'A' and ch <= 'Z';
404:     const flags: u8 = if (is_upper) 0x01 else 0x00;
405: 
406:     // ── LITERAL mode: just append ──
407:     if (s.mode == 1) {
408:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
409:         return 1;
410:     }
411: 
412:     // ── Check if first char triggers LITERAL mode ──
413:     if (s.len == 0) {
414:         if (lo == 'f' or lo == 'j' or lo == 'w' or lo == 'z') {
415:             enterLiteral(s);
416:             if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
417:             return 1;
418:         }
419:         // First char: just append as a regular span
420:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
421:         return 1;
422:     }
423: 
424:     // ── dd → đ ──
425:     if (lo == 'd') {
426:         // Look for last 'd' span without modifier
427:         if (s.len > 0) {
428:             const last_idx = s.len - 1;
429:             const last = &s.spans[last_idx];
430:             if (toLower(last.base) == 'd' and last.modifier == 0) {
431:                 // Cancellation: if already đ, undo
432:                 if (last.modifier == 'd') {
433:                     // Already handled above: modifier is 0 here
434:                     unreachable;
435:                 }
436:                 last.modifier = 'd';
437:                 return 1;
438:             }
439:         }
440:         // Regular d consonant
441:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
442:         autoFillUO(s);
443:         return 1;
444:     }
445: 
446:     // ── Doubled vowel modifier: aa→â, ee→ê, oo→ô ──
447:     if (lo == 'a' or lo == 'e' or lo == 'o') {
448:         if (s.len > 0) {
449:             const last_idx = s.len - 1;
450:             const last = &s.spans[last_idx];
451:             if (toLower(last.base) == lo and spanIsVowel(last.*)) {
452:                 if (last.modifier == lo) {
453:                     // Cancellation: modifier already applied → strip it, append plain vowel
454:                     last.modifier = 0;
455:                     last.tone = 0;
456:                     if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
457:                     return 1;
458:                 }
459:                 if (last.modifier == 0) {
460:                     last.modifier = lo;
461:                     return 1;
462:                 }
463:             }
464:         }
465:     }
466: 
467:     // ── w modifier ──
468:     if (lo == 'w') {
469:         // Look for target vowel: last a/o/u in the word
470:         var target: ?u8 = null;
471:         var i: u8 = 0;
472:         while (i < s.len) : (i += 1) {
473:             const b = toLower(s.spans[i].base);
474:             if (b == 'a' or b == 'o' or b == 'u') {
475:                 target = i;
476:             }
477:         }
478:         if (target) |ti| {
479:             const sp = &s.spans[ti];
480:             if (sp.modifier == 'w') {
481:                 // Cancellation: same modifier pressed again → enter literal
482:                 enterLiteral(s);
483:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
484:                 return 1;
485:             }
486:             if (sp.modifier != 0) {
487:                 // Already has a different modifier, can't apply w
488:                 // Treat w as a regular character → literal
489:                 enterLiteral(s);
490:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
491:                 return 1;
492:             }
493:             sp.modifier = 'w';
494:             autoFillUO(s);
495:             // Re-apply tone placement since modified vowel changed
496:             const ct = currentTone(s);
497:             if (ct != 0) applyTone(s, ct);
498:             return 1;
499:         }
500:         // No target vowel: if at start or no vowels, enter literal
501:         enterLiteral(s);
502:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
503:         return 1;
504:     }
505: 
506:     // ── Tone marks: s, f, r, x, j ──
507:     if (lo == 's' or lo == 'f' or lo == 'r' or lo == 'x' or lo == 'j') {
508:         const r = computeRegions(s);
509:         if (r.has_nucleus) {
510:             const ct = currentTone(s);
511:             if (ct == lo) {
512:                 // Cancellation: same tone pressed again → strip tone, enter literal
513:                 enterLiteral(s);
514:                 if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
515:                 return 1;
516:             }
517:             applyTone(s, lo);
518:             return 1;
519:         }
520:         // No nucleus vowels: treat as consonant
521:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
522:         return 1;
523:     }
524: 
525:     // ── z: tone reset or literal ──
526:     if (lo == 'z') {
527:         const ct = currentTone(s);
528:         if (ct != 0) {
529:             // Remove tone from all vowels
530:             var i: u8 = 0;
531:             while (i < s.len) : (i += 1) {
532:                 if (spanIsVowel(s.spans[i])) {
533:                     s.spans[i].tone = 0;
534:                 }
535:             }
536:             return 1;
537:         }
538:         // No tone to reset → enter literal
539:         enterLiteral(s);
540:         if (!appendSpan(s, ch, 0, 0, flags | 0x02)) return overflowReset(s);
541:         return 1;
542:     }
543: 
544:     // ── Vowels ──
545:     if (isVowel(lo)) {
546:         if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
547:         autoFillUO(s);
548:         // Re-apply tone placement after adding a vowel
549:         const ct = currentTone(s);
550:         if (ct != 0) applyTone(s, ct);
551:         return 1;
552:     }
553: 
554:     // ── Consonants ──
555:     if (!appendSpan(s, ch, 0, 0, flags)) return overflowReset(s);
556:     autoFillUO(s);
557:     return 1;
558: }
