560: export fn get_composed_utf16(state: *anyopaque, buf: [*]u16, buf_len: u16) u16 {
561:     const s: *State = @ptrCast(@alignCast(state));
562:     var pos: u16 = 0;
563: 
564:     var i: u8 = 0;
565:     while (i < s.len) : (i += 1) {
566:         if (pos >= buf_len) return 0xFF; // buffer overflow
567: 
568:         const sp = s.spans[i];
569: 
570:         // Literal spans: emit raw base character
571:         if (sp.flags & 0x02 != 0) {
572:             buf[pos] = @intCast(sp.base);
573:             pos += 1;
574:             continue;
575:         }
576: 
577:         const cp = lookupCodepoint(sp.base, sp.modifier, sp.tone);
578:         buf[pos] = cp;
579:         pos += 1;
580:     }
581: 
582:     return pos;
583: }

